#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long k;
        scanf("%lld", &k);
        long long ans = (k % 2 == 0) ? k : k + 2;
        printf("%lld\n", ans);
    }
    return 0;
}

